    provider_id,
    service_id,
    start_time,
    user_name,
    chat_id,
    idempotency_key: sanitizedKey,
    _meta: { source: 'WF2_ORCHESTRATOR', version: '2.3.2', timestamp: new Date().toISOString() }
  };

  return [{ json: { success: true, ctx } }];

